import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const AdminPage = ({ user }) => {
  const [report, setReport] = useState(null);
  const [draws, setDraws] = useState([]);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    if (!user || user.role !== 'admin') { navigate('/login'); return; }
    fetchReport();
    fetchDraws();
  }, [user]);

  const fetchReport = async () => {
    try {
      const { data } = await axios.get('/admin/reports');
      setReport(data);
    } catch (err) {
      setError(err.response?.data?.message || 'Unable to get report');
    }
  };

  const fetchDraws = async () => {
    try {
      const { data } = await axios.get('/draws');
      setDraws(data);
    } catch (err) {
      setError('Unable to fetch draws');
    }
  };

  const createDraw = async () => {
    const month = prompt('Month (1-12):');
    const year = prompt('Year:');
    try {
      await axios.post('/draws', { month: Number(month), year: Number(year) });
      fetchDraws();
    } catch (err) {
      setError('Failed to create draw');
    }
  };

  if (!user || user.role !== 'admin') return null;

  return (
    <div style={{maxWidth:'1000px', margin:'0 auto', padding:'20px'}}>
      <h2>Admin Dashboard</h2>
      {error && <p style={{ color:'red' }}>{error}</p>}
      <button onClick={createDraw}>Create New Draw</button>
      <section style={{marginTop:'20px'}}>
        <h3>Reports</h3>
        {report ? (
          <ul>
            <li>Total users: {report.totalUsers}</li>
            <li>Active users: {report.activeUsers}</li>
            <li>Total draws: {report.drawCount}</li>
            <li>Ticket count: {report.ticketCount}</li>
            <li>Total prize pool: ${report.totalPrizePool}</li>
          </ul>
        ) : (
          <p>Loading...</p>
        )}
      </section>
      <section style={{marginTop:'20px'}}>
        <h3>Draws</h3>
        <ul>
          {draws.map(d => (
            <li key={d._id}>
              {d.month}/{d.year} - {d.status}
              {d.status === 'draft' && <button onClick={() => axios.post(`/draws/${d._id}/simulate`).then(fetchDraws)}>Simulate</button>}
              {d.status === 'simulated' && <button onClick={() => axios.post(`/draws/${d._id}/publish`).then(fetchDraws)}>Publish</button>}
            </li>
          ))}
        </ul>
      </section>
    </div>
  );
};

export default AdminPage;
